#![allow(non_camel_case_types)]
#![allow(non_snake_case)]
#![allow(non_upper_case_globals)]
#![feature(c_variadic)]
#![feature(extern_types)]
#![feature(linkage)]
#![feature(rustc_private)]
#![feature(thread_local)]
#![feature(formatting_options)]
#![feature(as_array_of_cells)]

// === driver.rs ===
pub(crate) fn printLine(line: &[i8]) {
    if !line.is_empty() {
        println!(
            "{0}",
            std::ffi::CStr::from_bytes_until_nul(bytemuck::cast_slice(line))
                .unwrap()
                .to_str()
                .unwrap()
        );
    }
}

fn helperBad() -> *mut i8 {
    let mut charString: [i8; 17] = [
        b'h' as i8,
        b'e' as i8,
        b'l' as i8,
        b'p' as i8,
        b'e' as i8,
        b'r' as i8,
        b'B' as i8,
        b'a' as i8,
        b'd' as i8,
        b' ' as i8,
        b's' as i8,
        b't' as i8,
        b'r' as i8,
        b'i' as i8,
        b'n' as i8,
        b'g' as i8,
        b'\0' as i8,
    ];
    charString.as_mut_ptr()
}

pub(crate) unsafe fn bad() {
    printLine({
        let _x = helperBad();
        if _x.is_null() {
            &[]
        } else {
            std::slice::from_raw_parts(_x, 100000)
        }
    });
}

fn helperGood1() -> *mut i8 {
    thread_local! {
        static charString: std::cell::RefCell<[i8; 19]> = const {
            std::cell::RefCell::new([
                b'h' as i8,
                b'e' as i8,
                b'l' as i8,
                b'p' as i8,
                b'e' as i8,
                b'r' as i8,
                b'G' as i8,
                b'o' as i8,
                b'o' as i8,
                b'd' as i8,
                b'1' as i8,
                b' ' as i8,
                b's' as i8,
                b't' as i8,
                b'r' as i8,
                b'i' as i8,
                b'n' as i8,
                b'g' as i8,
                b'\0' as i8,
            ])
        };
    };

    // Return a stable pointer to the thread-local buffer without borrowing it.
    // This matches the intended C behavior (pointer remains valid for the thread).
    charString.with(|cell| cell.as_ptr() as *mut i8)
}

pub(crate) unsafe fn good() {
    printLine({
        let _x = helperGood1();
        if _x.is_null() {
            &[]
        } else {
            std::slice::from_raw_parts(_x, 100000)
        }
    });
}

#[no_mangle]
pub unsafe extern "C" fn driver(useGood: i32) {
    if useGood != 0 {
        good();
    } else {
        bad();
    };
}

